using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public class WeatherTools
{
    [McpServerTool(Name = "get_weather", ReadOnly = true),
     Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetWeather(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await client.GetFromJsonAsync<WeatherResponse>(url);

        if (response?.Current is null)
            return "No weather data available.";

        var c = response.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h";
    }

    [McpServerTool(Name = "get_forecast", ReadOnly = true),
     Description("Get a 7-day daily forecast for a location.")]
    public async Task<string> GetForecast(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&daily=temperature_2m_max,temperature_2m_min&forecast_days=7";

        var response = await client.GetFromJsonAsync<ForecastResponse>(url);

        if (response?.Daily is null)
            return "No forecast data available.";

        var lines = response.Daily.Time.Select((date, i) =>
            $"{date}: {response.Daily.MinTemp[i]}–{response.Daily.MaxTemp[i]}°C");

        return string.Join("\n", lines);
    }
}

// JSON models for the Open-Meteo API

public record WeatherResponse(
    [property: JsonPropertyName("current")] CurrentWeather? Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")] double Temperature,
    [property: JsonPropertyName("wind_speed_10m")] double WindSpeed);

public record ForecastResponse(
    [property: JsonPropertyName("daily")] DailyForecast? Daily);

public record DailyForecast(
    [property: JsonPropertyName("time")] string[] Time,
    [property: JsonPropertyName("temperature_2m_max")] double[] MaxTemp,
    [property: JsonPropertyName("temperature_2m_min")] double[] MinTemp);

